// This Code node expects input like:
// { "output": "{\n  \"Company Name\": \"...\",\n  \"Person Name\": [ ... ]\n}" }

const item = $input.item.json;

// 1) Get the raw string from the Switch output
const rawText = (item.output || "").trim();

if (!rawText) {
  return [{
    json: {
      error: "Missing 'output' field or it's empty",
      received: item
    }
  }];
}

// 2) rawText should already be JSON (starts with { or [), but we also support cases
// where extra text appears and we need to extract the JSON block.
let jsonString = rawText;

// If it doesn't start with { or [, try extracting the first JSON object/array
if (!(jsonString.startsWith("{") || jsonString.startsWith("["))) {
  const objMatch = jsonString.match(/\{[\s\S]*\}/);
  const arrMatch = jsonString.match(/\[[\s\S]*\]/);
  const match = objMatch || arrMatch;

  if (!match) {
    return [{
      json: {
        error: "No JSON found in 'output' string",
        received_text: rawText
      }
    }];
  }

  jsonString = match[0];
}

// 3) Parse
let parsed;
try {
  parsed = JSON.parse(jsonString);
} catch (e) {
  return [{
    json: {
      error: "JSON.parse failed on 'output'",
      details: e.message,
      raw: rawText
    }
  }];
}

// 4) Normalize format:
// If parsed is an array, try to find the first object that has "Company Name"
let data = parsed;
if (Array.isArray(parsed)) {
  data = parsed.find(x => x && typeof x === "object" && x["Company Name"]) || parsed[0] || {};
}

// 5) Extract fields
const companyName = data["Company Name"] || "Unknown";
const people = Array.isArray(data["Person Name"]) ? data["Person Name"] : [];

// 6) If no people, return one item (keeps workflow stable)
if (people.length === 0) {
  return [{
    json: {
      company_name: companyName,
      status: "No people found",
      original: data
    }
  }];
}

// 7) Output one item per person
return people.map(person => ({
  json: {
    company_name: companyName,
    name: person?.name ?? "NA",
    title: person?.title ?? "NA",
    email: person?.email ?? "NA",
    linkedin: person?.LinkedIn ?? "NA",
    instagram: person?.Instagram ?? "NA",
    twitter: person?.Twitter ?? "NA",
    facebook: person?.Facebook ?? "NA"
  }
}));
